2142 /// Test whether a GEP's result is known to be non-null.
2143 ///
2144 /// Uses properties inherent in a GEP to try to determine whether it is known
2145 /// to be non-null.
2146 ///
2147 /// Currently this routine does not support vector GEPs.
2148 static bool isGEPKnownNonNull(const GEPOperator *GEP, unsigned Depth,
2149                               const SimplifyQuery &Q) {
2150   const Function *F = nullptr;
2151   if (const Instruction *I = dyn_cast<Instruction>(GEP))
2152     F = I->getFunction();
2153 
2154   if (!GEP->isInBounds() ||
2155       NullPointerIsDefined(F, GEP->getPointerAddressSpace()))
2156     return false;
2157 
2158   // FIXME: Support vector-GEPs.
2159   assert(GEP->getType()->isPointerTy() && "We only support plain pointer GEP");
2160 
2161   // If the base pointer is non-null, we cannot walk to a null address with an
2162   // inbounds GEP in address space zero.
2163   if (isKnownNonZero(GEP->getPointerOperand(), Depth, Q))
2164     return true;
2165 
2166   // Walk the GEP operands and see if any operand introduces a non-zero offset.
2167   // If so, then the GEP cannot produce a null pointer, as doing so would
2168   // inherently violate the inbounds contract within address space zero.
2169   for (gep_type_iterator GTI = gep_type_begin(GEP), GTE = gep_type_end(GEP);
2170        GTI != GTE; ++GTI) {
2171     // Struct types are easy -- they must always be indexed by a constant.
2172     if (StructType *STy = GTI.getStructTypeOrNull()) {
2173       ConstantInt *OpC = cast<ConstantInt>(GTI.getOperand());
2174       unsigned ElementIdx = OpC->getZExtValue();
2175       const StructLayout *SL = Q.DL.getStructLayout(STy);
2176       uint64_t ElementOffset = SL->getElementOffset(ElementIdx);
2177       if (ElementOffset > 0)
2178         return true;
2179       continue;
2180     }
2181 
2182     // If we have a zero-sized type, the index doesn't matter. Keep looping.
2183     if (Q.DL.getTypeAllocSize(GTI.getIndexedType()).isZero())
2184       continue;
2185 
2186     // Fast path the constant operand case both for efficiency and so we don't
2187     // increment Depth when just zipping down an all-constant GEP.
2188     if (ConstantInt *OpC = dyn_cast<ConstantInt>(GTI.getOperand())) {
2189       if (!OpC->isZero())
2190         return true;
2191       continue;
2192     }
2193 
2194     // We post-increment Depth here because while isKnownNonZero increments it
2195     // as well, when we pop back up that increment won't persist. We don't want
2196     // to recurse 10k times just because we have 10k GEP operands. We don't
2197     // bail completely out because we want to handle constant GEPs regardless
2198     // of depth.
2199     if (Depth++ >= MaxAnalysisRecursionDepth)
2200       continue;
2201 
2202     if (isKnownNonZero(GTI.getOperand(), Depth, Q))
2203       return true;
2204   }
2205 
2206   return false;
2207 }
